var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"뭘 멍하니 서 있는 거냐?","JPN":"何をボケっとしてるんだ？","ENG":"Don’t just stand there dozing off like that!","TWN":"你呆呆站在這裡幹嘛？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"약물로 강화된 일반인이라고 해도 침식체들을 수족으로 부리는 놈들이다.","JPN":"薬物で強化された一般人とはいえ、侵食体を手懐けているやつらだ。","ENG":"These guys may seem like nothing more than fanatics, but they can control C.O.'s.","TWN":"就算是透過藥物強化的一群人，他們也都是把侵蝕體當成手下使喚的傢伙。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"넋 놓고 있다간 황천 가기 딱 좋아.","JPN":"しっかりしないと、あっという間にあの世行きだぞ。","ENG":"If you keep spacing out like that, you’ll be dead sooner than later.","TWN":"在你發呆的時候可能就把小命給丟了。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......그냥 궁금한 게 있어서요.","JPN":"……ちょっと、気になることがあって。","ENG":"I was just... curious about something.","TWN":"……我只是有件事有點好奇而已。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"궁금한 것? 그게 뭔데?","JPN":"気になること？　何だそれは？","ENG":"Curious? About what?","TWN":"好奇的事情？是什麼？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"글쎄요......","JPN":"そうですね……","ENG":"I'm not sure...","TWN":"這個嘛……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"물어보면 대답은 해 주실 건가요?","JPN":"聞いたら答えてくれますか？","ENG":"Would you answer me if I asked?","TWN":"如果我問的話，妳就會回答嗎？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"곤란한 일이 있으면 입을 다무는 건 여전하시네요.","JPN":"答えに困ることには、相変わらず口をつぐむんですね。","ENG":"Ah, you always go mute whenever things get difficult.","TWN":"還是萬一覺得困擾的話，妳就會像以往一樣，什麼都不說呢？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하긴, 제가 남의 이야기 할 처지는 아니겠죠. 하하.","JPN":"そりゃ、僕も人のことは言えませんが、ハハ。","ENG":"Then again, I’m in no place to judge. Haha.","TWN":"不過說實在的，我好像也沒有說別人的資格，哈哈。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"너.......","JPN":"お前……","ENG":"You...","TWN":"你……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"습격해 온 분들도 다 도망친 것 같으니, 슬슬 이동할 준비나 하겠습니다.","JPN":"襲ってきた方も全員逃げたようなので、そろそろ移動の準備でもします。","ENG":"Looks like everyone bailed on us now, so I’ll just prepare for our next movement.","TWN":"襲擊我們的人似乎都逃走了，我們差不多該準備前進了。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐야? 둘이서 무슨 이야기했어?","JPN":"二人でなに話してたの？","ENG":"Huh? What were you guys talking about?","TWN":"怎麼了？你們兩個聊了什麼？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"소대장 얼굴이 영 별로인데.","JPN":"小隊長の顔色が悪いんだけど。","ENG":"The Commander has this awful look on her face.","TWN":"小隊長的臉色怎麼不太好的樣子。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양.","JPN":"ミナさん。","ENG":"Mina.","TWN":"米娜小姐。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"왜? ......왜, 정색하고 그래?","JPN":"なに？　……真顔になったりして、どうしたの？","ENG":"Huh? Why... are you acting so serious all of a sudden?","TWN":"幹嘛？幹嘛……這麼嚴肅？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"우린 지금 왜 여기에 와 있는 걸까요?","JPN":"僕たちは今、なぜここに来ているのでしょうか？","ENG":"Have you ever wondered why we ended up coming here?","TWN":"我們為什麼會來這裡？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......뜬금없이 무슨 소리야?","JPN":"……いきなり何の話?","ENG":"Where did that come from?","TWN":"……你莫名其妙地問這個幹嘛？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"강소영 경위님은 실비아 양의 요청을 받아 여기에 왔죠.","JPN":"マエカワ警部補はシルビアさんの要請を受け、ここに来ましたよね。","ENG":"Lieutenant Kang came here per Sylvia's request.","TWN":"姜素英警衛是受到希爾維亞小姐請託，所以才來這裡的。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그리고 실비아 양은 스승님에게 요청을 받아 강소영 경위님을 찾아냈고요.","JPN":"そしてシルビアさんは、師匠からの要請で、マエカワ警部補を探し出しました。","ENG":"And Sylvia sought out the Lieutenant per the Master’s request.","TWN":"而希爾維亞小姐是受到師父的請託，才把姜素英警衛找來的。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그런데 스승님은 대체 어떻게 엘릭서라는 약물이 이번 사태와 관련이 있다는 사실을 알고 있었을까요?","JPN":"ところで師匠は、いったいどうしてエリクサーという薬物が今回の件と関連があるとわかったんですかね？","ENG":"But how did the Master know the Elixir had something to do with this case?","TWN":"但師父到底是怎麼知道聖水和這次的事件有關呢？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그건.......","JPN":"それは……","ENG":"Well...","TWN":"這個……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"좀 궁금하긴 해도, 아직 무슨 관계가 있다고 확인된 건 아니잖아?","JPN":"ちょっと気にはなるけど、まだ何か関係があると確定したわけじゃないでしょ？","ENG":"I guess that does seem rather curious, but we can't be sure there’s a connection there, can we?","TWN":"這的確讓人有點好奇，但還不能確定這之間有什麼關係吧？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나도 잘은 모르지만....... 그냥 헛수고일 수도 있고.","JPN":"私もよくわからないけど……ただの当てずっぽうかもしれないじゃん？","ENG":"I mean, I wouldn’t know... but it might just be nothing.","TWN":"我也不知道……說不定這沒有什麼關係。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아니요.","JPN":"いいえ。","ENG":"No.","TWN":"不。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양은 스승님을 만난 지 얼마 되지 않아 잘 모르겠지만......","JPN":"ミナさんは師匠と知り合ったばかりで、まだよく知らないと思いますが……","ENG":"You might not know this since you've met the Master only recently...","TWN":"米娜小姐和師父認識沒多久，所以不太知道……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"전 잘 알고 있어요.","JPN":"僕はよく知っています。","ENG":"but I’m very well aware of how she operates.","TWN":"但是我非常清楚 。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"스승님은 절대 이유 없이 움직이는 분이 아닙니다.","JPN":"師匠は絶対に理由もなく動く方ではありません。","ENG":"The Master never does anything without a reason.","TWN":"師父絕對不是沒有理由就行動的人。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"남들 눈을 의식하느라 이리저리 둘러서 움직이고 있지만......","JPN":"人目を気にして、遠回りをしながら動いてはいますが……","ENG":"She hasn’t be as straightforward lately, in order to ward off any unwanted suspicion...","TWN":"雖然她會避人耳目，不讓別人注意到……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"스승님은 분명 이 사건의 배후도, 엘릭서와 로스트 쉽의 관계에 대해서도 알고 있을 겁니다.","JPN":"師匠は、きっとこの事件の裏も、エリクサーとロストシップの関係についてもご存じのはずです。","ENG":"But I bet the Master is well aware of who’s behind this, and the connection between the Lost Ship and Elixir.","TWN":"但這次事件的幕後主謀、聖水和失落艦船的關係，師父肯定都知道吧。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그건....... 아무리 그래도 너무 억측 같은데.......","JPN":"それは……いくらなんでも憶測すぎるんじゃ……","ENG":"But... That just sounds like a wonky conspiracy theory to me.","TWN":"這……但不管怎麼說，這都只是你的猜測。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"마치 소대장이 이 모든 일의 흑막이라는 말 같잖아?","JPN":"まるで、小隊長がこの一連の事件の黒幕みたいじゃない。","ENG":"You make it sound as if the Commander's the real mastermind behind all this!","TWN":"而且這好像在說小隊長就是所有事件的黑幕一樣耶？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 물론 그 정도는 아니겠지만요.","JPN":"ハハハ、さすがにそこまではないと思いますが……","ENG":"Haha, of course, that would be stretch.","TWN":"哈哈，這倒是不至於。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그래도 한 가지 정도는 저도 추측할 수 있을 것 같네요.","JPN":"まあそれでも、一つくらいは僕も当てられそうです。","ENG":"But I do have one hypothesis.","TWN":"不過就算這樣，我還是能推測到某件事情。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"엘릭서의 효능 중에 즉사할 정도의 상처를 입은 자를 기적적으로 소생시킨다는 게 있었죠?","JPN":"エリクサーの効能で、即死するほどの傷を負った者を奇跡的に復活させるというものがありましたよね？","ENG":"Remember what they said about how the Elixir can heal people with critical wounds?","TWN":"在聖水的效果中，有一個是能讓受到致命傷的人奇蹟般地復活對吧？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......그런데?","JPN":"……そうだけど?","ENG":"So?","TWN":"……所以呢？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"어디선가 들어본 이야기 같지 않나요?","JPN":"この話、どこかで聞いてませんか？","ENG":"Doesn’t that sound familiar?","TWN":"妳不覺得這事情好像在哪裡聽過嗎？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"예를 들어 미나 양의 친구......","JPN":"たとえばミナさんの友達……","ENG":"Like your friend, for instance...","TWN":"例如說，米娜小姐的朋友……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"리플레이서 비숍이라든가.","JPN":"リプレイサー・ビショップとか。","ENG":"A.k.a. the Replacer Bishop...","TWN":"或者克隆·大主教……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......!!","JPN":"……！！","ENG":"......!!","TWN":"……！！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"다른 건 몰라도 엘릭서와 리플레이서가 관련이 있는 건 확실할 겁니다.","JPN":"他のことはわかりませんが、エリクサーとリプレイサーの間に何らかの関係があるのは確かでしょうね。","ENG":"One thing is clear. The Elixir must have something to do with the Replacer.","TWN":"就算我不知道其他的事情，但是聖水和克隆集團肯定有關係。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런.......","JPN":"そんな……","ENG":"But...","TWN":"這……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......미나 양.","JPN":"……ミナさん。","ENG":"Mina...","TWN":"……米娜小姐。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"왜, 왜 또?","JPN":"な、何？","ENG":"What now?","TWN":"幹嘛？又怎麼了？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"전 미나 양에게 아주 관심이 많습니다.","JPN":"僕はミナさんにとても興味があります。","ENG":"I’m very interested in you.","TWN":"我對妳越來越感興趣了。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......무, 무슨 소릴!!","JPN":"……な、何言ってるの！！","ENG":"W-what are you talking about!","TWN":"……什麼？你說什麼！！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"왜냐하면 스승님께서 미나 양에게 관심이 많기 때문이죠.","JPN":"なぜなら師匠がミナさんに興味津々だからです。","ENG":"That’s because the Master is very interested in you.","TWN":"因為師父非常在意妳。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"대체 선배는 뭘 생각하고 있는 거야?","JPN":"いったい先輩は何を考えてるの？","ENG":"What the heck is going through your head?","TWN":"前輩你到底在想什麼？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"알다가도 속을 모르겠어.","JPN":"何を考えているのか、さっぱりわからないよ。","ENG":"I can never figure you out.","TWN":"真不知你的腦袋到底是怎麼想的。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 그러게 말입니다.","JPN":"ハハ、ですよね。","ENG":"Haha, I know.","TWN":"哈哈，就是說啊。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"저도 잘 모르겠네요. 제가 무슨 생각을 하고 있는 건지.","JPN":"僕もよくわかりません。自分が何を考えているのか。","ENG":"Maybe I’m confused as well. I’m not quite sure what I’m thinking either.","TWN":"我也不是很清楚呢，我自己在想什麼……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 한 가지는 말해 두고 싶네요.","JPN":"ただ、これだけは言っておきたいですね。","ENG":"But I do want to make one thing clear.","TWN":"但是有一件事，我想要先說好。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양에겐 제가 비밀이 많은 사람처럼 보이겠지만.......","JPN":"ミナさんには僕が隠し事の多い人間に見えるでしょうけど……","ENG":"I may seem like a very secretive person to you...","TWN":"在米娜小姐眼中，我大概是個秘密很多的人吧……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"진짜 비밀이 많은 사람은 스승님입니다.","JPN":"本当に隠し事の多い人は、師匠です。","ENG":"But the person with lots of secrets is actually the Master.","TWN":"但是秘密真正多的人是師父。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"제 경험이지만...... 진실은 숨길수록 가시가 되어 돌아오는 법이죠.","JPN":"僕の経験ですが、真実は隠せば隠すほど、棘になって返ってくるものです。","ENG":"I speak from experience when I say... the more you try to hide the truth, the thornier it gets when you're about to step on it.","TWN":"雖然這是我個人的經驗……但越是隱瞞真相，真相就越是會變成一根傷人的刺。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"부디 그 가시에 미나 양이 찔리지 않았으면 좋겠군요.","JPN":"どうかその棘が、ミナさんに刺さることがないよう願っています。","ENG":"I just hope you don’t get pricked by those thorns.","TWN":"但願米娜小姐不要被刺傷就好了。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};